,"11.6":`<svg viewBox="0 0 520 128" style="width:100%;height:auto" xmlns="http://www.w3.org/2000/svg"><text x="260" y="12" text-anchor="middle" font-size="8" fill="#7A9688" font-family="monospace" letter-spacing=".1em">MAINTENANCE PLANNING AND LUMEN DEPRECIATION</text><rect x="8" y="20" width="242" height="98" rx="5" fill="#FAF5F0" stroke="#DDD0C0" stroke-width=".5"/><text x="129" y="38" text-anchor="middle" font-size="9" fill="#2F4A3F" font-weight="500">Maintenance cycle planning</text><text x="129" y="53" text-anchor="middle" font-size="8" fill="#7A9688">LLD: lumen depreciation over life</text><text x="129" y="67" text-anchor="middle" font-size="8" fill="#7A9688">LDD: dirt on optical surfaces</text><text x="129" y="81" text-anchor="middle" font-size="8" fill="#C65A3A">Combined = Light Loss Factor</text><text x="129" y="95" text-anchor="middle" font-size="8" fill="#7A9688">LLF drives fixture count</text><rect x="270" y="20" width="242" height="98" rx="5" fill="#e8f5ee" stroke="#7E9B86" stroke-width=".8"/><text x="391" y="38" text-anchor="middle" font-size="9" fill="#7E9B86" font-weight="500">Group relamping strategy</text><text x="391" y="53" text-anchor="middle" font-size="8" fill="#7A9688">Replace all at interval</text><text x="391" y="67" text-anchor="middle" font-size="8" fill="#7E9B86">vs spot replacement</text><text x="391" y="81" text-anchor="middle" font-size="8" fill="#7E9B86">LED: longer intervals</text><text x="391" y="95" text-anchor="middle" font-size="8" fill="#7A9688">Driver failure monitoring</text></svg>`
,"12.1":`<svg viewBox="0 0 520 128" style="width:100%;height:auto" xmlns="http://www.w3.org/2000/svg"><text x="260" y="12" text-anchor="middle" font-size="8" fill="#7A9688" font-family="monospace" letter-spacing=".1em">OFFICE AND WORKPLACE LIGHTING</text><rect x="8" y="20" width="242" height="98" rx="5" fill="#FAF5F0" stroke="#DDD0C0" stroke-width=".5"/><text x="129" y="38" text-anchor="middle" font-size="9" fill="#2F4A3F" font-weight="500">Workplace standards</text><text x="129" y="53" text-anchor="middle" font-size="8" fill="#7A9688">300-500 lux task plane</text><text x="129" y="67" text-anchor="middle" font-size="8" fill="#7E9B86">UGR 19 or less</text><text x="129" y="81" text-anchor="middle" font-size="8" fill="#7E9B86">Uniformity 1:3</text><text x="129" y="95" text-anchor="middle" font-size="8" fill="#7A9688">Individual dimming LEED</text><rect x="270" y="20" width="242" height="98" rx="5" fill="#e8f5ee" stroke="#7E9B86" stroke-width=".8"/><text x="391" y="38" text-anchor="middle" font-size="9" fill="#7E9B86" font-weight="500">Activity-based working</text><text x="391" y="53" text-anchor="middle" font-size="8" fill="#7A9688">Focus zones: 500 lux</text><text x="391" y="67" text-anchor="middle" font-size="8" fill="#7E9B86">Collaboration: 300 lux</text><text x="391" y="81" text-anchor="middle" font-size="8" fill="#7E9B86">Lounge: 100-200 lux</text><text x="391" y="95" text-anchor="middle" font-size="8" fill="#7A9688">Tunable white circadian</text></svg>`
